#ifndef DEFAULT_ORDER
#define DEFAULT_ORDER 256
#endif

typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    uchar is_leaf;
    uchar _pad[3];
    int num_keys;
} knode;

__kernel void findK(long maxheight,
                    __global knode *knodes,
                    long knodes_elem,
                    __global record *records,
                    __global long *currKnode,
                    __global long *offset,
                    __global int *keys,
                    __global record *ans)
{
    const size_t bid = get_group_id(0);
    const size_t lid = get_local_id(0);

    if (lid != 0)
        return;

    long curr = currKnode[bid];
    long off = offset[bid];
    const int key = keys[bid];
    const int threadsPerBlock = (int)get_local_size(0);

    for (long i = 0; i < maxheight; i++) {
        for (int thid = 0; thid < threadsPerBlock; thid++) {
            if ((knodes[curr].keys[thid] <= key) &&
                (knodes[curr].keys[thid + 1] > key)) {
                if (knodes[off].indices[thid] < knodes_elem) {
                    off = (long)knodes[off].indices[thid];
                }
            }
        }
        curr = off;
    }

    for (int thid = 0; thid < threadsPerBlock; thid++) {
        if (knodes[curr].keys[thid] == key) {
            ans[bid].value = records[knodes[curr].indices[thid]].value;
        }
    }

    currKnode[bid] = curr;
    offset[bid] = off;
}

